content.problemStatement:
Consider the following C++ code that initializes a 2D array with student marks and prints them. What will be the output of this code?

```cpp
#include 
using namespace std;

int main() {
    // Declare and initialize a 2D array with student marks for 3 subjects
    int marks[3][3] = {
        {75, 80, 85},  // Marks for Student 1
        {70, 75, 80},  // Marks for Student 2
        {90, 92, 95}   // Marks for Student 3
    };

    // Access and print elements of the 2D array
    cout << marks[0][0] << " " << marks[1][0] << " " << marks[2][0] << endl;
    cout << marks[0][1] << " " << marks[1][1] << " " << marks[2][1] << endl;
    cout << marks[0][2] << " " << marks[1][2] << " " << marks[2][2] << endl;

    return 0;
}
```

